INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('25-sales-os',3,25,'SALES OS','He dieu hanh ban hang',25,'draft','2026-06-20T15:52:11Z','2026-06-20T15:52:11Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0c59e439-8578-4cc5-a5a9-b5b38f72d179','25-sales-os',NULL,2,'25.1 Vai trò của Sales OS trong hệ điều hành Dental Empire','251-vai-tro-cua-sales-os-trong-he-ieu-hanh-dental-empire',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('62fcc90a-55fc-42bf-868d-91094fcfe356','0c59e439-8578-4cc5-a5a9-b5b38f72d179',0,'image',NULL,'book/25-sales-os/88852a2e-e759-4aa2-9858-508d368dd09e-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d68c3912-4157-4632-a55e-3ec48b0f3200','0c59e439-8578-4cc5-a5a9-b5b38f72d179',1,'text','Trong kiến trúc tổng thể của **Dental Empire OS**, **Sales OS** đóng vai trò là bộ van điều tiết tối cao cho nguồn data do **Marketing OS** (trái tim bơm máu) mang về. Phân hệ này loại bỏ hoàn toàn cách tư vấn bản năng bằng một đường ống chuyển đổi chuẩn y khoa:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bfc955eb-922d-4d16-a63f-cb8e92561562','0c59e439-8578-4cc5-a5a9-b5b38f72d179',2,'text','- **Sàng lọc nhu cầu:** Phân loại đúng điểm đau thực tế của khách.- **Tư vấn thấu cảm:** Bẻ gãy các rào cản hoài nghi và sợ đau.- **Khóa lịch hẹn (Booking):** Điều hướng chính xác giờ giấc để tối ưu công suất ghế nha.- **Bám đuổi (Follow-up):** Kiên trì sưởi ấm lòng tin đối với tệp khách hàng đang do dự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f24d63ec-85e5-41c3-b608-1c4a52cc86d9','0c59e439-8578-4cc5-a5a9-b5b38f72d179',3,'text','**Kết quả:** Biến những tương tác vô tri trên mạng thành bệnh nhân thực tế bước vào phòng khám, sẵn sàng hợp tác với phác đồ điều trị của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4958a916-cd78-48eb-917a-5e135188bb7c','0c59e439-8578-4cc5-a5a9-b5b38f72d179',4,'text','Quy trình Sales tuyệt đối không bị hiểu sai thành việc "chốt lịch hẹn bằng mọi giá" hay thao túng tâm lý khách hàng. Ở đây, Sales OS đóng vai trò là một trục liên kết dài hạn, kết nối chặt chẽ các mắt xích trải nghiệm của bệnh nhân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79c13198-7e8e-40cb-ad35-154b5a013dda','0c59e439-8578-4cc5-a5a9-b5b38f72d179',5,'image',NULL,'book/25-sales-os/90aad136-bcf4-4483-b99c-4c5088965346-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4dee9cd6-ba10-479f-9212-7de2d548a1bd','0c59e439-8578-4cc5-a5a9-b5b38f72d179',6,'text','Nếu thiếu đi sự kiểm soát nghiêm ngặt của Sales OS, phòng khám sẽ rơi vào trạng thái rò rỉ năng lượng nghiêm trọng. Khách hàng sau khi bị thu hút bởi các nội dung giáo dục y khoa thường thức trên TikTok hoặc website sẽ nhanh chóng rời bỏ hành trình nếu gặp phải sự chậm trễ trong khâu trực inbox, hoặc tông giọng tư vấn thiếu sự thấu cảm của nhân sự tuyến đầu. Sales OS ra đời để chặn đứng mọi sự thất thoát dữ liệu tại các điểm chạm nhạy cảm này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5cda1051-7d6e-4722-aca1-e2a913ae0349','25-sales-os',NULL,2,'25.2 Tư duy cốt lõi: làm rõ rào cản và bán sự an tâm','252-tu-duy-cot-loi-lam-ro-rao-can-va-ban-su-an-tam',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8532e916-139e-4286-8e89-54c411c3a286','5cda1051-7d6e-4722-aca1-e2a913ae0349',7,'text','Tư duy thượng tầng định hình toàn bộ hành vi của đội ngũ tư vấn trực thuộc phòng khám RHM được đóng gói qua một nguyên lý bất di dịch: **Bán hàng trong nha khoa tử tế không phải là hoạt động thương mại hóa dịch vụ y tế, mà là quá trình làm rõ nỗi sợ và gỡ bỏ rào cản ra quyết định của bệnh nhân.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7baef48a-5385-40f2-ae29-5614a2ff654d','5cda1051-7d6e-4722-aca1-e2a913ae0349',8,'text','Bệnh nhân khi tìm đến nha khoa luôn mang theo những tổn thương và sự hoang mang tâm lý tầng sâu. Vì vậy, kịch bản giao tiếp của Sales OS được thiết kế để thực thi 6 nhiệm vụ cốt lõi hằng ngày:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44a70508-f9eb-4a42-88fe-ad0755dc5258','5cda1051-7d6e-4722-aca1-e2a913ae0349',9,'text','- **Lắng nghe chủ động:** Đào sâu vào điểm đau thực tế, thấu hiểu lịch sử điều trị lỗi hoặc những bất tiện trong sinh hoạt hằng ngày của khách hàng trước khi đưa ra giải pháp.- **Thấu suốt nhu cầu thực:** Phân tách rõ ràng giữa nhu cầu bề nổi (muốn làm răng sứ rẻ, muốn niềng răng nhanh) với khát vọng thực tế tầng sâu (muốn tự tin giao tiếp để thăng tiến, muốn ăn nhai ngon miệng để cải thiện sức khỏe).- **Bao bọc bằng sự an tâm:** Sử dụng tri thức sạch và thái độ tử tế để xoa dịu nỗi sợ hãi sinh học cốt lõi (sợ đau buốt, sợ biến chứng đào thải vật liệu).- **Giảng thuật giải pháp trực quan:** Chuyển đổi toàn bộ thuật ngữ lâm sàng khô khan thành ngôn từ thường thức bình dân giúp bệnh nhân dễ dàng thấu hiểu và làm chủ phác đồ điều trị.- **Triệt tiêu rào cản tài chính:** Hóa giải các lo ngại về chi phí phát sinh bằng cách minh bạch hóa bảng giá trọn gói ngay từ đầu và cấu hình các giải pháp thanh toán linh hoạt, trả góp an toàn.- **Điều hướng bước tiếp theo:** Luôn kết thúc cuộc hội thoại bằng một chỉ dẫn rõ ràng, dứt khoát, dẫn dắt bệnh nhân tiến tới mốc hành động tiếp theo (đặt hẹn đặt lịch hoặc nhận tài liệu dặn dò y khoa).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b32b108-b136-490c-a909-2f5553ad3626','5cda1051-7d6e-4722-aca1-e2a913ae0349',10,'text','Mục tiêu tối hậu của phân hệ này không phải là dùng các thủ thuật sales để ép khách mua hàng cấp tốc, mà là cung cấp đầy đủ bằng chứng khoa học và sự chân thành để khách hàng có đủ niềm tin vững chắc, tự nguyện đặt lịch hẹn và bước vào lộ trình điều trị dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b1856300-e70e-491d-9a4c-ff35c104b47b','25-sales-os',NULL,2,'25.3 Vị trí chiến lược của Sales OS trong hệ điều hành tổng thể','253-vi-tri-chien-luoc-cua-sales-os-trong-he-ieu-hanh-tong-the',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00a335fe-0f1c-41ff-a8ed-d273868ccb50','b1856300-e70e-491d-9a4c-ff35c104b47b',11,'text','Trong kiến trúc vận hành tổng thể của hệ điều hành, Sales OS đóng vai trò là điểm chuyển giao thông tin mang tính sống còn, chịu trách nhiệm tiếp nhận năng lượng từ tầng truyền thông và chuyển giao tài sản dữ liệu xuống cho tầng lâm sàng sàn. Sự liên kết này được lập trình vận hành theo một đường ống đồng bộ khép kín:',NULL,NULL,NULL,NULL,NULL);
