INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6937d1e9-1db3-42da-be6c-da9ca88da65c','b1856300-e70e-491d-9a4c-ff35c104b47b',14,'text','Tập trung sản xuất kho nội dung giáo dục thường thức, xây dựng uy tín chuyên gia cho Bác sĩ sáng lập Nguyễn Phước Vinh để thu nạp nguồn lead nóng sạch đầu phễu.',NULL,NULL,NULL,NULL,NULL);
