INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa436656-0345-4f92-b76b-0ed7b01d69c4','b1856300-e70e-491d-9a4c-ff35c104b47b',17,'text','Tiếp nhận data từ Marketing, thực thi các kịch bản phá băng, phân loại tệp khách, hóa giải rào cản hoài nghi từ xa để khóa chặt lịch hẹn Booking về sàn phòng khám.',NULL,NULL,NULL,NULL,NULL);
