INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1384a049-5e6f-417e-80b1-8304508bf671','b1856300-e70e-491d-9a4c-ff35c104b47b',19,'text','*Clinic OS vận hành.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a9980788-b612-402d-8ca9-8ad51fcdedf3','b1856300-e70e-491d-9a4c-ff35c104b47b',20,'text','Bác sĩ đón tiếp khách show-up, tiến hành chụp phim CT Cone Beam chẩn đoán, lên phác đồ điều trị chi tiết tại ghế nha và thực thi thủ thuật chuyên môn chuẩn SOP y khoa.',NULL,NULL,NULL,NULL,NULL);
