INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4c3bb4f-ddf0-4f53-8d1b-b5642689d8af','b1856300-e70e-491d-9a4c-ff35c104b47b',22,'text','*Patient OS tiếp quản.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('583fe59a-d978-4f06-9dba-f616684ef5dc','b1856300-e70e-491d-9a4c-ff35c104b47b',23,'text','Kích nổ đường ống tự động dặn dò hậu phẫu, chạy luồng Recall tái khám bảo trì định kỳ trọn đời để duy trì mối quan hệ bền vững với bộ tộc hội viên.',NULL,NULL,NULL,NULL,NULL);
