INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21ef8ec6-9b72-4421-8344-1eaca0a6e54b','b1856300-e70e-491d-9a4c-ff35c104b47b',25,'text','*Referral OS đóng vòng lặp.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca72216f-6bba-4e66-b31a-7220b3f2d1be','b1856300-e70e-491d-9a4c-ff35c104b47b',26,'text','Biến sự hạnh phúc của bệnh nhân cũ thành dòng tài sản đánh giá 5 sao và dòng khách giới thiệu truyền miệng tự nhiên có chi phí sắm khách (CAC) bằng 0.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a93505b-a91e-4a31-9ffe-84ba9a0b7259','25-sales-os',NULL,2,'25.4 Sáu mục tiêu chiến lược định lượng đầu ra','254-sau-muc-tieu-chien-luoc-inh-luong-au-ra',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01dd46e6-81b5-4f91-8989-b61a5a5ec06c','9a93505b-a91e-4a31-9ffe-84ba9a0b7259',27,'text','Để giải phóng phòng khám RHM tại Hà Nội khỏi trạng thái quản trị theo cảm tính, Sales OS bắt buộc phải được kiểm soát hằng ngày bằng 6 mục tiêu định lượng cụ thể:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('87f01616-7548-400e-83a0-9f966d8a4668','9a93505b-a91e-4a31-9ffe-84ba9a0b7259',28,'text','- **Tối ưu hóa tốc độ phản hồi (Response Time SLA):** Đánh chặn tâm lý nóng lòng của bệnh nhân bằng cách phản hồi mọi dòng inbox, hotline dưới mốc thời gian vàng là 3 phút kể từ khi phát sinh lead trên CRM.- **Bứt phá tỷ lệ đặt lịch hẹn (Booking Rate):** Chuyển hóa tối thiểu 45% lượng lead sạch đổ về thành các mã lịch hẹn được xác lập chính thức trên hệ thống phần mềm.- **Gia tăng chỉ số khách có mặt thực sàn (Show-up Rate):** Thực thi nghiêm ngặt đường ống gọi điện dặn dò và xác nhận mã hẹn trước 24 giờ để đẩy tỷ lệ Show-up thực tế tại phòng khám đạt mốc lớn hơn hoặc bằng 70%.- **Triệt tiêu tuyệt đối sự thất thoát dữ liệu:** Số hóa 100% hồ sơ thông tin khách hàng, đảm bảo không có bất kỳ một lead nào bị bỏ quên hoặc rơi ra ngoài đường ống theo dõi của bộ phận quản lý.- **Chuẩn hóa cấu trúc quy trình tư vấn sàn:** Đóng gói toàn bộ các kịch bản inbox, kịch bản telesales và kịch bản phối hợp tư vấn tại phòng VIP thành các tài liệu SOP cứng, loại bỏ hoàn toàn thói quen giao tiếp ngẫu hứng của nhân sự.- **Kiến tạo kho dữ liệu đối soát tài chính:** Xuất báo cáo tiến độ phễu chuyển đổi thời gian thực hằng ngày hằng tuần, cung cấp nguyên liệu sạch để *Data OS* thực hiện hạch toán chỉ số ROI chính xác cho từng chiến dịch tiếp thị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('432b5cb9-9668-4790-8209-5630c4226ed6','25-sales-os',NULL,2,'25.5 Sales Funnel trong phòng khám nha khoa','255-sales-funnel-trong-phong-kham-nha-khoa',4,'[]');
