INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('61177139-eacc-4ed7-bd50-df25bcf45d81','25-sales-os',NULL,2,'25.6 Ma trận phân loại khách hàng và chiến thuật xử lý thực chiến','256-ma-tran-phan-loai-khach-hang-va-chien-thuat-xu-ly-thuc-chien',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('438b6fd3-412a-414a-8284-d296266b9a31','61177139-eacc-4ed7-bd50-df25bcf45d81',30,'text','Hệ điều hành quy định toàn bộ nhân sự tư vấn không được phép dùng chung một kịch bản giao tiếp cho mọi đối tượng. Khách hàng đổ về hệ thống nha khoa bắt buộc phải được phân loại nghiêm ngặt thành 4 nhóm phân khúc dựa trên độ ấm của lòng tin và tính cấp bách của nhu cầu, từ đó áp dụng các chiến thuật xử lý biệt lập:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('64d1d5d5-18bb-4bbc-834b-43ac6027225c','61177139-eacc-4ed7-bd50-df25bcf45d81',31,'image',NULL,'book/25-sales-os/edeb14f5-32bc-4eb6-bfc6-bdb79ba263af-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a0d7c2c5-40a6-43e1-a392-3d389bf264ce','25-sales-os',NULL,2,'25.6 Quy trình 10 bước điều hành và chuyển đổi Lead tiêu chuẩn (The Core Conversion Flow)','256-quy-trinh-10-buoc-ieu-hanh-va-chuyen-oi-lead-tieu-chuan-the-core-conversion-',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ab93ad2b-f8cf-43a1-80d9-fcec6b623b86','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',32,'text','Để triệt tiêu hoàn toàn tính ngẫu hứng và ngăn chặn tình trạng rò rỉ dữ liệu, hệ điều hành quy định mọi hồ sơ khách hàng khi nạp vào hệ thống của nha khoa **Thích Làm Răng** bắt buộc phải dịch chuyển tuần tự qua đúng trục dọc 10 bước xử lý chuẩn hóa dưới đây. Nhân sự tuyệt đối không được nhảy cóc quy trình hoặc cắt xén các điểm chạm tâm lý của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c0917521-d750-489d-8431-39ffc5e23f04','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 1: TIẾP NHẬN VÀ MÃ HÓA DỮ LIỆU ĐẦU PHỄU','buoc-1-tiep-nhan-va-ma-hoa-du-lieu-au-pheu',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb0e2f52-5809-4eb7-9de0-394a17995b59','c0917521-d750-489d-8431-39ffc5e23f04',33,'text','Mọi luồng dữ liệu phát sinh từ không gian mạng hoặc đến trực tiếp bắt buộc phải được quy hoạch tập trung về một cổng CRM duy nhất trong vòng 60 giây.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1e82894-a988-4c6e-b95d-d803f8fae8b4','c0917521-d750-489d-8431-39ffc5e23f04',34,'text','- **Các nguồn tiếp nhận huyết mạch:***Mạng xã hội:* Facebook Messenger Inbox, Tiktok Comment/Inbox.- *Hạ tầng số:* Website Form đăng ký từ, Google Business Profile (Google Maps Action).- *Kênh trực tiếp:* Hotline tổng đài phòng khám, Sự kiện Livestream/Webinar y khoa định kỳ.- *Nguồn hữu cơ:* Khách hàng cũ giới thiệu (Referral Network), đối tác liên kết địa phương tại Hà Nội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('914be897-16f2-4786-ac60-539ce061708a','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 2: ĐÁNH CHẶN TỐC ĐỘ - PHÂN HỒI ĐẦU TIÊN (SLA &lt; 3 PHÚT)','buoc-2-anh-chan-toc-o-phan-hoi-au-tien-sla-lt-3-phut',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('69c55d20-eb83-411d-8a24-b86b57ec1a07','914be897-16f2-4786-ac60-539ce061708a',35,'text','Nguyên tắc bất di dịch của chặng này là **Đánh chặn tâm lý khẩn cấp**. Khách hàng đang lướt mạng xã hội có hành vi hỏi nhiều nha khoa cùng lúc, người phản hồi trước với thái độ tử tế nhất sẽ chiếm 80% cơ hội chiến thắng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f5d1e17-60a4-4bcb-9911-d179be197233','914be897-16f2-4786-ac60-539ce061708a',36,'text','**Bộ kỷ luật thép "4 KHÔNG" khi trực Inbox:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5c2d4a8d-a646-451a-a25c-359bbd6aad38','914be897-16f2-4786-ac60-539ce061708a',37,'text','- **KHÔNG** trả lời máy móc bằng các câu lệnh AI vô tri hoặc văn bản sao chép khô khan.- **KHÔNG** bắn bảng giá dịch vụ ngay lập tức khi chưa khai thác và thấu hiểu điểm đau lâm sàng của khách.- **KHÔNG** sử dụng các thuật ngữ chuyên môn sâu (Ví dụ: tiêu xương vùng hốc, khớp cắn hạng III) gây hoang mang cho người đọc.- **KHÔNG** bao giờ kết thúc dòng tin nhắn bằng một câu khẳng định cụt lủn, luôn mở ra một câu hỏi điều hướng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e3aa9343-70f9-41c8-b6ed-9ecc63707ca0','914be897-16f2-4786-ac60-539ce061708a',38,'text','**Mẫu văn bản phá băng tiêu chuẩn:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15e8dd3a-f85f-4f4f-8a2c-95726522b968','914be897-16f2-4786-ac60-539ce061708a',39,'text','- "*Dạ em chào anh/chị ạ. Em nhận được thông tin mình đang cần hỗ trợ về sức khỏe răng miệng rồi ạ. Hiện tại mình đang quan tâm đến giải pháp niềng răng thẩm mỹ, răng sứ bảo tồn hay cấy ghép Implant chuyên sâu vậy anh/chị? Anh/chị có thể chia sẻ giúp em tình trạng răng hiện tại hoặc mô tả qua bất tiện mình đang gặp phải để em hỗ trợ tư vấn sát nhất cho mình nhé ạ!"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('caa0ada8-e05c-4e21-b7b2-102a9b6dbc55','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 3: GIẢI PHẪU ĐIỂM ĐAU - KHAI THÁC NHU CẦU TẦNG SÂU','buoc-3-giai-phau-iem-au-khai-thac-nhu-cau-tang-sau',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7348d9e-8699-4d5c-a6e5-0828757f176c','caa0ada8-e05c-4e21-b7b2-102a9b6dbc55',40,'text','Nhân sự tư vấn đóng vai trò là người trợ lý y khoa sưởi ấm lòng tin, thực hiện đặt câu hỏi để bóc tách trọn vẹn **5 Khung Kích Thước Dữ Liệu** của bệnh nhân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('016e9135-6671-4a25-9c9a-6b21c3806f9d','caa0ada8-e05c-4e21-b7b2-102a9b6dbc55',41,'text','- **Vấn đề sinh học hiện tại:** Khách đang bị lệch lạc, hô, móm, mất răng lâu năm hay đau nhức cấp tính?- **Khát vọng đích cuối:** Mong muốn cải thiện chức năng ăn nhai đơn thuần, nâng cấp thẩm mỹ nụ cười để thăng tiến công việc hay giải quyết triệt để cơn đau?- **Lịch sử điều trị:** Trước đây đã từng đi thăm khám, niềng răng hỏng hay cấy trụ lỗi ở phòng khám nào chưa?- **Rào cản tâm lý cốt lõi:** Điều khách lo lắng nhất đang kìm hãm họ ra quyết định là gì? Chi phí đắt, thời gian kéo dài, sợ đau buốt sinh học hay sợ biến chứng hậu phẫu?- **Quỹ thời gian thực tế:** Khách làm việc hành chính hay tự do, có thể thu xếp đến cơ sở Hà Nội vào ngày nào trong tuần?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('41b946d1-3f3f-4f98-b457-a3ec2a3ac0d6','caa0ada8-e05c-4e21-b7b2-102a9b6dbc55',42,'text','- **Hệ thống câu hỏi mẫu trực chiến:***"Dạ hiện tại răng mình đang gặp tình trạng khấp khểnh, mất răng ăn nhai khó khăn hay có dấu hiệu đau nhức vùng nướu rồi ạ?"*- *"Mình đang mong muốn ưu tiên cải thiện về thẩm mỹ nụ cười tự tin hay muốn khôi phục lại chức năng ăn nhai khỏe mạnh nhiều hơn ạ?"*- *"Trước đây mình đã từng đi chụp phim hay thực hiện can thiệp điều trị ở đâu chưa anh/chị nhỉ?"*- *"Dạ điều mình đang băn khoăn, đắn đo nhất lúc này là vấn đề chi phí, thời gian điều trị, sợ đau sinh học hay độ bền hiệu quả sau này vậy ạ? Anh/chị cứ chia sẻ thật lòng để em tìm giải pháp phù hợp nhất cho mình nhé."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2a05f15a-764a-48b6-a76b-7546bad3c43b','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 4: TƯ VẤN ĐỊNH HƯỚNG - THIẾT LẬP TÍNH CẦN THIẾT CỦA LÂM SÀNG','buoc-4-tu-van-inh-huong-thiet-lap-tinh-can-thiet-cua-lam-sang',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96b07f65-0aea-4bb4-8c21-4361dfc59d1c','2a05f15a-764a-48b6-a76b-7546bad3c43b',43,'text','Nhân sự Sales Online tuyệt đối không được phép đưa ra kết luận chẩn đoán thay cho Bác sĩ điều trị. Việc phán bừa bệnh lý qua mạng là hành vi vi phạm y đức và tự làm giảm uy tín chuyên gia của phòng khám. Mục tiêu của bước này là giúp bệnh nhân hiểu rõ **Bản chất của việc thăm khám trực tiếp thực sàn**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d9edcc3-a142-4ca4-81c7-daa3e5e15911','2a05f15a-764a-48b6-a76b-7546bad3c43b',44,'text','**Kịch bản định hướng điều hướng ghế nha:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4aba42e0-15fa-499c-aed1-4956ee46cf78','2a05f15a-764a-48b6-a76b-7546bad3c43b',45,'text','- *"Dạ với những biểu hiện răng hiện tại như anh/chị vừa mô tả, trên góc độ chuyên môn y khoa, có thể tình trạng của mình cần được Bác sĩ kiểm tra trực tiếp trên cung hàm và tiến hành chụp phim CT Cone Beam để khảo sát chính xác mật độ xương cũng như chân răng nằm sâu bên dưới. Có những vấn đề nhìn bằng mắt thường sẽ không thấy hết được ạ.*- *Sau khi có kết quả phim chụp cụ thể, Bác sĩ Nguyễn Phước Vinh cùng đội ngũ chuyên môn mới có thể lập cho mình một phác đồ cá nhân hóa, lúc đó mình sẽ biết rõ lộ trình đi răng ra sao, thời gian bao lâu và chi phí trọn gói minh bạch là bao nhiêu anh/chị ạ."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('05e99b8c-a43d-4047-8336-e01fb219d164','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 5: KHUẾCH ĐẠI NIỀM TIN - BƠM TÀI SẢN THỰC CHỨNG (TRUST ASSETS INJECTION)','buoc-5-khuech-ai-niem-tin-bom-tai-san-thuc-chung-trust-assets-injection',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23ccc40e-7232-4406-b004-c4270a19ec9f','05e99b8c-a43d-4047-8336-e01fb219d164',46,'text','Khi khách bắt đầu có dấu hiệu lo lắng hoặc im lặng, nhân sự lập tức kích hoạt kho đạn dược truyền thông từ *Trust Asset System* để bẻ gãy bộ lọc phòng thủ tâm lý của khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f900369d-8481-4f02-9d9f-f30347a790e5','05e99b8c-a43d-4047-8336-e01fb219d164',47,'text','- **Hành động vận hành:** Gửi chính xác 1 bộ tư liệu bao gồm: Ảnh Before/After ca lâm sàng tương tự, 1 link bài đánh giá Review 5 sao của người thật trên Google Maps, hoặc 1 đoạn video ngắn Bác sĩ Vinh giải thích công nghệ không đau bằng ngôn từ thường thức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1ba609f-e0f5-487e-98b0-516d9a9bb8c4','05e99b8c-a43d-4047-8336-e01fb219d164',48,'text','**Mẫu hội thoại mẫu:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4813c445-70ef-403d-b826-49f92c3e80ae','05e99b8c-a43d-4047-8336-e01fb219d164',49,'text','- *"Dạ để mình an tâm hơn, em xin phép gửi anh/chị xem qua hình ảnh và video hành trình lột xác của một anh khách bên em, tình trạng ban đầu của anh ấy cũng gần như y hệt răng của mình hiện tại ạ. Ca này do trực tiếp Bác sĩ Vinh lên phác đồ điều trị. Bây giờ anh ấy đã hoàn tất lắp răng, ăn nhai hoàn toàn thoải mái và nụ cười cực kỳ tự nhiên rồi, anh/chị xem tham khảo nhé ạ!"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c702d7d2-b7b4-4f87-b006-9a0f18f1164f','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 6: ĐỀ XUẤT ĐẶT LỊCH HẸN BẰNG KỸ THUẬT LỰA CHỌN THAY THẾ (ALTERNATIVE CLOSING)','buoc-6-e-xuat-at-lich-hen-bang-ky-thuat-lua-chon-thay-the-alternative-closing',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7c440fb-000c-4de0-9cec-8a61abb025a6','c702d7d2-b7b4-4f87-b006-9a0f18f1164f',50,'text','Tuyệt đối không sử dụng các câu hỏi Có/Không (Yes/No Question) như: *"Anh/chị có muốn đặt lịch hẹn không?"* vì kịch bản này tạo ma sát tâm lý lớn, cho phép khách hàng đưa ra câu trả lời từ chối một cách dễ dàng. Hãy chủ động điều hướng bằng kỹ thuật đóng hai phương án lựa chọn đều hướng tới mốc hành động đến khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('099469d1-451a-4d6f-85a2-841449bc9216','c702d7d2-b7b4-4f87-b006-9a0f18f1164f',51,'text','**Mẫu kịch bản chốt lịch hẹn hiệu suất cao:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd8a42cf-bda8-470d-9113-803a8bd9e307','c702d7d2-b7b4-4f87-b006-9a0f18f1164f',52,'text','- *"Để giúp mình tiết kiệm thời gian và được Bác sĩ kiểm tra kỹ lưỡng nhất, em hỗ trợ đặt lịch hẹn giữ ghế nha và đăng ký suất chụp phim CT Cone Beam miễn phí cho mình tuần này nhé ạ. Phòng khám bên em hiện tại đang còn khung lịch trống vào chiều Thứ Năm hoặc sáng Thứ Bảy tuần này, không biết anh/chị tiện thu xếp qua cơ sở bên em vào buổi nào thuận tiện nhất cho công việc của mình ạ?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('46ceece4-7e04-42e1-b599-be8dc1872dad','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 7: XÁC NHẬN MÃ HẸN ĐỒNG BỘ VÀ KHÓA CÔNG SUẤT GHẾ','buoc-7-xac-nhan-ma-hen-ong-bo-va-khoa-cong-suat-ghe',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e99750f-66df-4246-b863-25183c68cbcb','46ceece4-7e04-42e1-b599-be8dc1872dad',53,'text','Khi khách đồng ý ngày giờ, Sales lập tức tạo lập mã lịch hẹn trên CRM, khóa khung giờ trống của ghế nha để tối ưu công suất sàn vận hành và gửi văn bản xác nhận trang trọng qua Zalo cá nhân của khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6dd343c8-9ad5-4bec-b55b-9a028a37038d','46ceece4-7e04-42e1-b599-be8dc1872dad',54,'text','**Mẫu văn bản xác nhận pháp định hệ thống:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6617dec5-68d8-404f-8350-c7fa2d2e99fb','46ceece4-7e04-42e1-b599-be8dc1872dad',55,'text','*(Lưu ý nhỏ: Suất hẹn của mình đã được đặt riêng một ghế nha và chuẩn bị sẵn bộ dụng cụ vô trùng khép kín. Nếu có bất kỳ thay đổi nào về mặt thời gian di chuyển, anh/chị vui lòng thông báo trước cho em 4 tiếng để em kịp điều phối lịch cho các bệnh nhân khác nhé ạ. Em cảm ơn anh/chị và chúc anh/chị một ngày vui vẻ!)*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d19260bb-53fa-4c4b-8001-6519045d5ace','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 8: QUY TRÌNH KIỂM SOÁT NO-SHOW NHẮC LỊCH CHU KỲ HAI TẦNG','buoc-8-quy-trinh-kiem-soat-no-show-nhac-lich-chu-ky-hai-tang',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('deeeb883-136d-4bf5-b6de-3a4ed6eaaceb','d19260bb-53fa-4c4b-8001-6519045d5ace',56,'text','Để ngăn chặn triệt để tình trạng khách quên lịch hẹn hoặc bùng lịch làm lãng phí công suất vận hành của Bác sĩ trực sàn, CSKH thực hiện nghiêm ngặt quy trình nhắc lịch hai tầng thời gian:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('efcb808c-c95c-4220-a049-70e60d3cd304','d19260bb-53fa-4c4b-8001-6519045d5ace',57,'text','**Tầng 1: Đối soát trước giờ hẹn 24 giờ (T-24h Confirmation)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1fe9e773-b884-4502-aa9e-1e69ae46457b','d19260bb-53fa-4c4b-8001-6519045d5ace',58,'text','**Mẫu tin nhắn/cuộc gọi:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('acece615-a687-46bb-9eb7-7e6f424069a2','d19260bb-53fa-4c4b-8001-6519045d5ace',59,'text','- *"Dạ em chào anh/chị, em là [Tên nhân sự] từ nha khoa Thích Làm Răng ạ. Em xin phép gọi điện nhắc lại lịch hẹn tầm soát răng miệng chuyên sâu của mình vào lúc [giờ] ngày mai tại phòng khám bên em ạ. Anh/chị vẫn thu xếp di chuyển qua đúng giờ hẹn ngày mai giúp em để Bác sĩ Vinh thăm khám và chụp phim kỹ lưỡng nhất cho mình nhé ạ."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2651bf8c-c96a-487b-9d77-92c2f0d7b364','d19260bb-53fa-4c4b-8001-6519045d5ace',60,'text','**Tầng 2: Kích hoạt trước giờ hẹn 2 - 3 giờ (T-2h Flash Reminder)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58135789-b0bb-48f6-84e4-9585042df2a7','d19260bb-53fa-4c4b-8001-6519045d5ace',61,'text','**Mẫu tin nhắn áp dụng công nghệ Local GEO:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4599009-710b-45ab-9ecf-839a8ca27b96','d19260bb-53fa-4c4b-8001-6519045d5ace',62,'text','- *"Dạ anh/chị ơi, em nhắc mình có lịch hẹn khám với Bác sĩ Vinh vào lúc [giờ] ngày hôm nay tại nha khoa ạ. Hiện tại phòng khám đã hoàn tất chuẩn bị phòng vô trùng sẵn sàng đón tiếp mình rồi ạ. Anh/chị có cần em gửi lại vị trí định vị Maps chính xác của phòng khám qua Zalo này để mình tiện di chuyển đường đi không ạ?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('acf7200e-0283-4c79-9430-42281a72e0bd','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 9: BIÊN BẢN BÀN GIAO ONLINE-TO-OFFLINE (HANDOFF PAYLOAD ĐẾN CLINIC OS)','buoc-9-bien-ban-ban-giao-online-to-offline-handoff-payload-en-clinic-os',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b9470454-4e10-4fd9-b95d-3b8785a9d773','acf7200e-0283-4c79-9430-42281a72e0bd',63,'text','Ngay khi khách hàng bước chân qua cửa phòng khám, bộ phận Sales Online thực hiện đẩy toàn bộ gói dữ liệu lịch sử tương tác số xuống cho Lễ tân quầy lễ tân và Bác sĩ trực ca qua hệ thống CRM. Tuyệt đối không bắt khách hàng phải ngồi trả lời lại từ đầu những gì họ đã chat trên không gian mạng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd3aa51b-4dab-4fc1-9cce-89cf2529ee87','acf7200e-0283-4c79-9430-42281a72e0bd',64,'text','**Mẫu cấu trúc Payload bàn giao nội bộ tiêu chuẩn:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be4b400f-cef6-4170-afac-652892cc4c33','acf7200e-0283-4c79-9430-42281a72e0bd',65,'image',NULL,'book/25-sales-os/baba3dd2-62c1-459a-9d2d-8337778036ff-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dd768c9a-b1ce-43ed-9e72-31003a9b61e1','25-sales-os','a0d7c2c5-40a6-43e1-a392-3d389bf264ce',3,'BƯỚC 10: PHÁ BĂNG HỒ SƠ HOÃN ĐIỀU TRỊ - KÍCH HOẠT  FOLLOW-UP HỆ THỐNG (LOST LEAD RECOVERY)','buoc-10-pha-bang-ho-so-hoan-ieu-tri-kich-hoat-follow-up-he-thong-lost-lead-recov',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8728067e-fcd7-4893-b665-f274c9fe9efe','dd768c9a-b1ce-43ed-9e72-31003a9b61e1',66,'text','Chặng cuối cùng của Sales OS xử lý nhóm bệnh nhân đã đến phòng khám, chụp phim CT Cone Beam, nhận phác đồ trực tiếp từ Bác sĩ nhưng **chưa xuống tiền điều trị ngay** mà ra về với lý do: *"Để anh/chị về suy nghĩ thêm"*, *"Để hỏi lại ý kiến gia đình"* hoặc im lặng vì cú sốc tài chính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd628e33-fd79-4ca1-a980-d70d996a374e','dd768c9a-b1ce-43ed-9e72-31003a9b61e1',67,'text','Một sai lầm chí mạng của nhân sự tư vấn là bỏ mặc tệp khách này vì nghĩ họ không có nhu cầu, hoặc liên tục nhắn tin chèo kéo ép sale khiến bệnh nhân phòng thủ, block số. Trong nha khoa tử tế, **Follow-up không phải là săn đuổi dòng tiền, mà là kiên trì sưởi ấm lòng tin và tái định vị giải pháp y khoa.** Bệnh nhân trì hoãn vì nỗi sợ của họ lớn hơn động lực thay đổi. Nhiệm vụ của Sales là dùng kỷ luật hệ thống để gỡ bỏ nỗi sợ đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5e717839-3504-4bb2-8d45-6ef6f9b31045','25-sales-os','dd768c9a-b1ce-43ed-9e72-31003a9b61e1',4,'10.1 Ma Trận Tần Suất Bám Đuổi Theo Chu Kỳ Thời Gian (The Follow-up Matrix)','101-ma-tran-tan-suat-bam-uoi-theo-chu-ky-thoi-gian-the-follow-up-matrix',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f093ca0-f6c4-439a-a41b-9ce62727ceb6','5e717839-3504-4bb2-8d45-6ef6f9b31045',68,'image',NULL,'book/25-sales-os/0446c5f2-b62e-4b26-b4a4-f2226a2745af-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8b91fa3a-ec74-4e6e-bb1d-26309c9214ca','25-sales-os','dd768c9a-b1ce-43ed-9e72-31003a9b61e1',4,'10.2 Bộ Kịch Bản Thực Chiến Phá Băng Rào Cản (Sales Script Playbook)','102-bo-kich-ban-thuc-chien-pha-bang-rao-can-sales-script-playbook',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1c151cd3-c4be-48ba-8d9e-5ca27344cbb2','8b91fa3a-ec74-4e6e-bb1d-26309c9214ca',69,'text','Kịch bản 1: Xử lý rào cản do dự do Áp lực tài chính (Bơm đòn bẩy dòng tiền)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ff2e2c2-3050-465b-aeae-bff996e3203a','8b91fa3a-ec74-4e6e-bb1d-26309c9214ca',70,'text','"Dạ em chào anh/chị, em là [Tên nhân sự] trợ lý y khoa của Bác sĩ Vinh tại nha khoa Thích Làm Răng đây ạ. Hôm trước mình qua khám, Bác sĩ Vinh có dặn em lưu ý đặc biệt ca của mình vì vùng xương hàm răng cấm đang có dấu hiệu tiêu dần do mất răng lâu năm, nếu để chậm thêm thì sau này cấy ghép sẽ phức tạp và tốn chi phí hơn rất nhiều ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9cfce6a8-f92b-49bc-8afd-b577cfc26e2d','8b91fa3a-ec74-4e6e-bb1d-26309c9214ca',71,'text','Em biết điều mình đắn đo nhất lúc này là việc phải chi trả một khoản chi phí lớn cùng một lúc đúng không anh/chị? Để giúp mình bảo vệ sức khỏe ăn nhai sớm mà không bị áp lực dòng tiền, em đã xin ý kiến ban giám đốc áp dụng riêng cho mình giải pháp **Trả góp an toàn 0% lãi suất thông qua ngân hàng**, mỗi tháng mình chỉ cần tích lũy một khoản nhỏ bằng tiền đi chợ thôi ạ. Không biết nếu thanh toán chia nhỏ linh hoạt như vậy thì đã thuận tiện cho kế hoạch tài chính của gia đình mình chưa anh/chị?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('efebcc4b-d125-4efc-86f4-d5265ea27608','8b91fa3a-ec74-4e6e-bb1d-26309c9214ca',72,'text','Kịch bản 2: Xử lý rào cản Sợ đau (Dùng nội dung giáo dục thường thức)',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ed37565-159c-4c64-8645-6ffb66b3c853','8b91fa3a-ec74-4e6e-bb1d-26309c9214ca',73,'text','"Dạ em chào anh/chị ạ. Sau buổi thăm khám phác đồ niềng răng hôm trước, em thấy mình cứ lo lắng mãi về việc phải nhổ răng khôn để tạo khoảng trống dịch chuyển cung hàm đúng không ạ? Em hiểu cảm giác lo sợ đau của mình, vì ai đối mặt với ghế nha cũng có tâm lý như vậy ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('74265248-3d24-45a3-b2ff-146453710812','8b91fa3a-ec74-4e6e-bb1d-26309c9214ca',74,'text','Để mình hoàn toàn yên tâm, em xin phép gửi mình xem đoạn video ngắn 90 giây Bác sĩ Vinh unboxing và giải thích về công nghệ nhổ răng sóng siêu âm Piezotome không đau hiện tại đang áp dụng thực tế tại phòng VIP bên em. Công nghệ này không chạm vào mô mềm nên hậu phẫu cực kỳ nhẹ nhàng, không sưng buốt như phương pháp truyền thống đâu ạ. Anh/chị xem qua để thấy việc đi răng thực ra rất nhẹ nhàng, đừng vì nỗi sợ mà hoãn lại nụ cười thẩm mỹ của mình nhé ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5d7c43f0-30a2-460f-b3d0-0433b12d0e99','25-sales-os','dd768c9a-b1ce-43ed-9e72-31003a9b61e1',4,'10.3 Tiêu Chuẩn Nghiệm Thu Đầu Ra Của Hồ Sơ Hoãn Điều Trị','103-tieu-chuan-nghiem-thu-au-ra-cua-ho-so-hoan-ieu-tri',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c8dd94a-15d3-45b1-85d9-9154d4207fbf','5d7c43f0-30a2-460f-b3d0-0433b12d0e99',75,'text','Một hồ sơ hoãn điều trị chỉ được phép đóng lại và chuyển trạng thái sang `LOST` (Mất lead hoàn toàn) trên CRM khi và chỉ khi nhân sự tư vấn đã thực hiện tối thiểu **4 cuộc gọi/nhắn tin chăm sóc** ở các góc độ khác nhau (Sức khỏe, Lòng tin, Giải pháp tài chính, Quà tặng tri thức) nhưng khách hàng kiên quyết từ chối hoặc không phản hồi. Toàn bộ lý do rớt ca phải được ghi chú minh bạch bằng dữ liệu số để làm nguyên liệu tối ưu hóa cho vòng lặp của *Optimization System*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fa5135ab-99cb-4ace-8bcb-6edbed101929','25-sales-os',NULL,2,'25.7 Quy trình Follow-Up chuẩn hóa theo độ ấm đường ống dữ liệu','257-quy-trinh-follow-up-chuan-hoa-theo-o-am-uong-ong-du-lieu',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b2b1086-8fbd-4a04-abb0-b55f0d3cba08','fa5135ab-99cb-4ace-8bcb-6edbed101929',76,'text','Trong hệ điều hành **Sales OS**, follow-up không phải là hành vi "nài nỉ" khách hàng mua dịch vụ, mà là cỗ máy sưởi ấm niềm tin có kỷ luật. Thống kê vận hành cho thấy 70% doanh thu của phòng khám RHM không đến từ lượt tương tác đầu tiên, mà đến từ các điểm chạm nuôi dưỡng phía sau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b283c2e6-1368-4039-9919-e24b9f7a7004','fa5135ab-99cb-4ace-8bcb-6edbed101929',77,'text','Để triệt tiêu hoàn toàn trạng thái nhân sự tư vấn bỏ rơi lead hoặc nhắn tin khủng bố khách hàng theo bản năng, Dental OS chuẩn hóa quy trình follow-up thành 3 kịch bản đường ống biệt lập dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('44841226-34ce-437b-bf7f-5d1be878ce5c','25-sales-os','fa5135ab-99cb-4ace-8bcb-6edbed101929',3,'Phần 1: Khách Chưa Đặt Lịch (Unbooked Leads)','phan-1-khach-chua-at-lich-unbooked-leads',21,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e8414890-4277-42f1-8345-ad0bcddeb849','25-sales-os','44841226-34ce-437b-bf7f-5d1be878ce5c',4,'Bối cảnh &amp; Tâm lý bệnh nhân','boi-canh-amp-tam-ly-benh-nhan',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f06f056b-bf18-4ca9-a617-79ac5ec63e47','e8414890-4277-42f1-8345-ad0bcddeb849',78,'text','Đây là tệp lead nạp từ **Marketing OS** (TikTok, Website, Fanpage), đã qua sàng lọc chuyên môn sơ bộ (`Qualified`), đã tương tác trò chuyện nhưng lập tức im lặng hoặc từ chối khéo (*"để anh xem đã", "có gì chị nhắn sau"*) ngay khi nhân sự tư vấn đề xuất chốt ngày giờ đặt lịch hẹn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c4d454d-531d-4b18-91a3-afca70f8b87f','e8414890-4277-42f1-8345-ad0bcddeb849',79,'text','- **Rào cản tâm lý:** Lòng tin chưa đủ dày, sợ bị lừa dối về giá, hoặc chưa cảm thấy tính cấp bách của bệnh lý để phải di chuyển đến phòng khám.- **Chiến thuật vận hành:** Tuyệt đối không ép lịch. Hãy dùng nội dung giáo dục thường thức (Education Content) và bằng chứng xã hội (Social Proof) để nuôi dưỡng từ xa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8a3abbe0-e015-44e1-acb2-19f6f736393e','25-sales-os','44841226-34ce-437b-bf7f-5d1be878ce5c',4,'Đường ống tiếp cận theo chu kỳ thời gian (Timeline)','uong-ong-tiep-can-theo-chu-ky-thoi-gian-timeline',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a7a5d22-4761-41c7-80bd-56d299f03ad0','8a3abbe0-e015-44e1-acb2-19f6f736393e',80,'image',NULL,'book/25-sales-os/5391edb2-f5fb-4f69-8a3d-82023ee76e4c-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('975a60f6-7d63-4ecc-942d-56a5c3dde9d3','25-sales-os','44841226-34ce-437b-bf7f-5d1be878ce5c',4,'Bộ kịch bản mẫu thực chiến (Scripts)','bo-kich-ban-mau-thuc-chien-scripts',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('761ee6ba-7a6c-4d3c-afe3-bc7a0e1ca120','975a60f6-7d63-4ecc-942d-56a5c3dde9d3',81,'text','**Mẫu T+24h (Gửi giá trị trước):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ee30fd3-d11a-4cf2-9337-9fcf176e6ee2','975a60f6-7d63-4ecc-942d-56a5c3dde9d3',82,'text','- "Dạ em chào anh/chị ạ. Hôm qua em có trao đổi và biết răng mình đang có dấu hiệu tiêu xương nướu do mất răng lâu năm. Bác sĩ Nguyễn Phước Vinh bên em vừa cho xuất bản cuốn *Cẩm nang bảo tồn xương hàm và răng thật tại nhà* dạng số hóa rất dễ hiểu.- Em xin phép gửi tặng anh/chị đọc tham khảo trước để biết cách ăn nhai khoa học, tránh làm ảnh hưởng đến các răng khỏe mạnh xung quanh nhé ạ. Anh/chị bấm vào link này để tải file nha!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00546240-7aac-4c60-a8ac-77f5201daa61','975a60f6-7d63-4ecc-942d-56a5c3dde9d3',83,'text','**Mẫu T+3 Ngày (Đánh động điểm đau):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('63ea8137-8f9d-45c7-8861-d19d7f396ff1','975a60f6-7d63-4ecc-942d-56a5c3dde9d3',84,'text','- "Dạ anh/chị ơi, hôm trước mình có nói răng khấp khểnh làm mình hay bị dắt thức ăn và hôi nướu đúng không ạ? Em gửi mình xem video ngắn 60 giây Bác sĩ Vinh phân tích về tác hại của việc để cao răng tích tụ sâu dưới nướu đối với người răng lệch lạc nha. Nếu để lâu rất dễ dẫn đến viêm nha chu gây lung lay răng sớm đó ạ.- Tuần này bên em đang có đợt tầm soát vôi răng siêu âm miễn phí bằng máy công nghệ cao cho tệp khách đăng ký qua TikTok, mình có muốn em giữ cho một suất qua kiểm tra sớm không ạ?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ea99fd96-5433-42bb-a382-4556205bba25','25-sales-os','fa5135ab-99cb-4ace-8bcb-6edbed101929',3,'Phần 2: Khách Đã Đặt Lịch Nhưng Chưa Đến (No-Show Leads)','phan-2-khach-a-at-lich-nhung-chua-en-no-show-leads',25,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cf48c484-bfa5-4d12-9c6f-cf3124635b6a','25-sales-os','ea99fd96-5433-42bb-a382-4556205bba25',4,'Bối cảnh &amp; Tâm lý bệnh nhân','boi-canh-amp-tam-ly-benh-nhan',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7e41ede-43cd-4202-9426-9575862ae1c8','cf48c484-bfa5-4d12-9c6f-cf3124635b6a',85,'text','Khách hàng đã đồng ý chốt mã hẹn, hệ thống đã khóa công suất ghế nha nhưng đến giờ hẹn khách **không xuất hiện thực sàn** (No-show) hoặc gọi điện hoãn lịch giờ chót.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6be4e150-fb0a-4711-aa9d-4fe20c127e79','cf48c484-bfa5-4d12-9c6f-cf3124635b6a',86,'text','- **Rào cản tâm lý:** Khách bận việc đột xuất thật, quên lịch, hoặc đột nhiên nỗi sợ đau sinh học trỗi dậy khiến họ hoảng sợ trốn hẹn. Ngoài ra, khách thường có tâm lý ngại ngùng, không dám chủ động inbox lại vì đã thất hứa.- **Chiến thuật vận hành:** Tạo lối thoát tâm lý cho khách (coi như việc họ bận là bất khả kháng), bao bọc bằng sự thấu cảm và tái kích hoạt bằng việc giữ lại đặc quyền ưu đãi giới hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9ee5cc57-ab0f-4de1-800f-2957e2e6c7f3','25-sales-os','ea99fd96-5433-42bb-a382-4556205bba25',4,'Đường ống tiếp cận theo chu kỳ thời gian (Timeline)','uong-ong-tiep-can-theo-chu-ky-thoi-gian-timeline',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e7bb5b38-bb74-4b61-94d4-0a058b4442d4','9ee5cc57-ab0f-4de1-800f-2957e2e6c7f3',87,'image',NULL,'book/25-sales-os/442503c6-70e9-4487-8876-01408ba7abe3-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0e5fbe00-86f8-4d74-b871-f2a06444f24e','25-sales-os','ea99fd96-5433-42bb-a382-4556205bba25',4,'Bộ kịch bản mẫu thực chiến (Scripts)','bo-kich-ban-mau-thuc-chien-scripts',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d5aeb7ba-782d-44e5-8ef0-0e4829622dac','0e5fbe00-86f8-4d74-b871-f2a06444f24e',88,'text','**Mẫu T+2h (Mở lối thoát tâm lý):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5127f408-91cf-40ae-a3b3-0200a3fc462a','0e5fbe00-86f8-4d74-b871-f2a06444f24e',89,'text','- "Dạ em chào anh/chị ạ. Chiều nay lúc 15:00 em thấy mình có lịch hẹn khám Implant với Bác sĩ Vinh nhưng chưa thấy mình qua sàn vận hành phòng khám. Không biết mình đang di chuyển trên đường gặp sự cố kẹt xe hay có công việc đột xuất gì không anh/chị nhỉ? Công việc bận rộn là chuyện bình thường nên anh/chị đừng ngại nhé. Em nhắn tin để hỏi thăm tình hình mình thôi ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('55cf7349-e8a6-4016-9631-750d1c7c4b06','0e5fbe00-86f8-4d74-b871-f2a06444f24e',90,'text','**Mẫu T+24h (Giữ đặc quyền để Re-book):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdfa72df-ec5c-455c-bc9e-82ba3fda4399','0e5fbe00-86f8-4d74-b871-f2a06444f24e',91,'text','- "Dạ anh/chị ơi, suất quà tặng chụp phim CT Cone Beam tầm soát xương hàm trị giá 1.500.000đ của mình hôm qua hệ thống tự động khóa lại do lỗi lịch hẹn ạ. Tuy nhiên, biết tình trạng răng của mình đang cần xử lý sớm để tránh tiêu xương, em đã chủ động làm việc với bộ phận quản lý để xin **gia hạn mã ưu đãi này thêm 48 giờ nữa**.- Trong hai ngày cuối tuần này, mình thuận tiện qua phòng khám vào sáng Thứ Bảy hay chiều Chủ Nhật để em báo Lễ tân chuẩn bị phòng vô trùng đón tiếp mình chu đáo ạ?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c9cde856-0ef1-41ae-abe4-499f77992405','25-sales-os','fa5135ab-99cb-4ace-8bcb-6edbed101929',3,'Phần 3: Khách Đã Khám Nhưng Chưa Điều Trị (Consulted Leads)','phan-3-khach-a-kham-nhung-chua-ieu-tri-consulted-leads',29,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('88cdc134-4fff-4846-ac62-cc81994d2c17','25-sales-os','c9cde856-0ef1-41ae-abe4-499f77992405',4,'Bối cảnh &amp; Tâm lý bệnh nhân','boi-canh-amp-tam-ly-benh-nhan',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('290cb45b-2796-4434-bacc-b33f8d9b9511','88cdc134-4fff-4846-ac62-cc81994d2c17',92,'text','Bệnh nhân đã đến phòng khám, đã hoàn tất chụp phim phim, nhận phác đồ điều trị chi tiết trực tiếp từ Bác sĩ nhưng **ra về mà chưa ký hợp đồng/chưa đóng tiền mặt thu trước (Upfront)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aad30121-c9d5-42dd-8165-d53277cbff02','88cdc134-4fff-4846-ac62-cc81994d2c17',93,'text','- **Rào cản tâm lý:** Sốc tài chính trước giá trị ca lâm sàng lớn (Implant toàn hàm, niềng răng Invisalign), cần thời gian bàn bạc với gia đình, hoặc lòng tin vào năng lực thực tế chưa đè bẹp được nỗi sợ rủi ro y khoa.- **Chiến thuật vận hành:** Gỡ bỏ áp lực thanh toán bằng đòn bẩy tài chính; liên tục dội bom kho bằng chứng thực chứng thành công (Social Proof) để bẻ gãy sự do dự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cc8625c5-6377-4ece-86a3-8f04180a0267','25-sales-os','c9cde856-0ef1-41ae-abe4-499f77992405',4,'Đường ống tiếp cận theo chu kỳ thời gian (Timeline)','uong-ong-tiep-can-theo-chu-ky-thoi-gian-timeline',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('31cd2283-e37f-4ec9-8f38-230c0799f420','cc8625c5-6377-4ece-86a3-8f04180a0267',94,'text','**Bộ kịch bản mẫu thực chiến (Scripts)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('757bed39-f9b7-4b6c-a767-148f8fe3833d','cc8625c5-6377-4ece-86a3-8f04180a0267',95,'text','**Mẫu T+24h (Nhắc nhở y khoa tử tế):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56be38f8-ba8e-48ed-93b2-d54578e0a90e','cc8625c5-6377-4ece-86a3-8f04180a0267',96,'text','- "Dạ em chào anh/chị. Hôm qua sau khi thăm khám trực tiếp, Bác sĩ Vinh có dặn em phải lưu ý nhắc nhở mình kỹ lưỡng ạ. Tình trạng chân răng sâu hỏng của mình đã chớm ảnh hưởng đến dây thần kinh vùng hàm, nếu trì hoãn nhổ bỏ và cấy Implant sớm thì ổ viêm sẽ lan rộng, làm sụt lún cấu trúc cơ mặt.- Anh/chị về nhà răng miệng có bị đau nhức hay bất tiện gì khi ăn uống không ạ? Nếu có điểm nào trong phác đồ hôm qua Bác sĩ giải thích mình chưa rõ, anh/chị cứ nhắn em để em xin ý kiến Bác sĩ làm rõ cho mình nhé."',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21042a9f-47af-4bac-87b5-1e3840e7099a','cc8625c5-6377-4ece-86a3-8f04180a0267',97,'text','**Mẫu T+3 Ngày (Dội bom bằng chứng thực tế):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7607d2e-1f66-4887-80da-c466284f6e15','cc8625c5-6377-4ece-86a3-8f04180a0267',98,'text','- "Dạ em chào anh/chị, em gửi mình xem một đoạn video ngắn hành trình lột xác nụ cười của một chị khách bên em ạ. Trước đây khi đến phòng khám, tình trạng răng hô lệch và thưa của chị ấy gần như chính xác 100% so với răng của mình hiện tại, chị ấy cũng từng đắn đo rất nhiều trước khi niềng răng.- Bây giờ sau 18 tháng đồng hành cùng Bác sĩ Vinh, chị ấy đã tháo niềng với diện mạo cực kỳ xinh đẹp rồi ạ. Anh/chị xem để có thêm động lực thay đổi nụ cười của mình sớm nhé ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98eef80c-9259-4475-8979-773b9ba420dc','cc8625c5-6377-4ece-86a3-8f04180a0267',99,'text','**Mẫu T+7 Ngày (Bẻ gãy rào cản tài chính tối hậu):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('df1b4822-bba4-40cb-8cd6-86758706498c','cc8625c5-6377-4ece-86a3-8f04180a0267',100,'text','- "Dạ anh/chị ơi, em biết điều mình đang đắn đo lớn nhất lúc này để kích hoạt phác đồ Implant là vấn đề chi phí phải chi trả một lúc đúng không ạ? Để giúp mình bảo vệ sức khỏe ăn nhai kịp thời mà không bị áp lực dòng tiền, nha khoa Thích Làm Răng đã liên kết thành công chính sách **Trả góp an toàn 0% lãi suất**.- Mình chỉ cần thanh toán trước một khoản nhỏ, số còn lại được chia đều trả theo tháng, tính ra mỗi ngày chỉ bằng chi phí một ly cà phê thôi ạ. Thanh toán linh hoạt như vậy đã giúp anh/chị dễ dàng thu xếp quyết định làm răng sớm chưa ạ?"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e8bf9b7d-9f22-4dd1-8812-b8887877359a','25-sales-os',NULL,2,'25.8 Tiêu Chuẩn SLA Phản Hồi Khách Hàng - Kỷ Luật Thời Gian Thép Trên Đường Ống Số','258-tieu-chuan-sla-phan-hoi-khach-hang-ky-luat-thoi-gian-thep-tren-uong-ong-so',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9744a1c0-316a-45ba-bc7c-04864c2e8839','e8bf9b7d-9f22-4dd1-8812-b8887877359a',101,'text','Trong kỷ nguyên số hóa y khoa năm 2026, **Tốc độ phản hồi chính là tử huyệt của tỷ lệ chuyển đổi**. Khách hàng khi để lại thông tin hoặc gửi tin nhắn hỏi về phác đồ chỉnh nha, Implant thường có xu hướng tìm kiếm và tương tác với từ 3 đến 5 phòng khám cùng một lúc. Người nào xuất hiện trước với sự thấu cảm và tốc độ đánh chặn nhanh nhất, người đó chiếm 80% cơ hội đưa khách hàng về ghế nha thực sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e22656c-4c4b-47cc-a3e3-27df86bee0c8','e8bf9b7d-9f22-4dd1-8812-b8887877359a',102,'text','Hệ điều hành **Sales OS** định nghĩa: **SLA (Service Level Agreement) phản hồi khách hàng không phải là một chỉ số khuyến khích, mà là một kỷ luật thời gian bắt buộc pháp định.** Nếu vi phạm SLA, dòng data sạch do Marketing dày công mang về sẽ bị nguội lạnh, đẩy chi phí CAC lên cao và trực tiếp làm rò rỉ dòng tiền mặt trả trước của nha khoa **Thích Làm Răng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('34a6fc0f-2f78-4e98-ac65-de05372a9ee8','25-sales-os','e8bf9b7d-9f22-4dd1-8812-b8887877359a',3,'Ma Trận Phân Tầng SLA Theo Kênh Tiếp Nhận Dữ Liệu','ma-tran-phan-tang-sla-theo-kenh-tiep-nhan-du-lieu',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f093e1cd-f8e0-428d-b3a4-e947224e42b8','34a6fc0f-2f78-4e98-ac65-de05372a9ee8',103,'text','Hệ thống CRM trung tâm cấu hình cứng thời gian vàng phản hồi đầu tiên (First Response Time) biệt lập cho từng điểm chạm, buộc nhân sự trực ca phải xử lý cấp tốc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b487fb1a-c6c4-4756-867c-310936246105','34a6fc0f-2f78-4e98-ac65-de05372a9ee8',104,'image',NULL,'book/25-sales-os/5c2ed944-89fc-4a7c-9c5f-f0619e378487-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e0044d62-7231-4269-975b-a32f8247391e','25-sales-os','e8bf9b7d-9f22-4dd1-8812-b8887877359a',3,'Sơ Đồ Đường Ống Xử Lý Leo Thang Khi Vi Phạm SLA (Escalation Path)','so-o-uong-ong-xu-ly-leo-thang-khi-vi-pham-sla-escalation-path',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1b30aa0b-1f0d-415c-85a9-0df1d06c41ef','e0044d62-7231-4269-975b-a32f8247391e',105,'text','Để triệt tiêu hoàn toàn tình trạng nhân sự lười biếng hoặc bỏ quên lead trong ca trực, hệ thống CRM tự động kích hoạt đường ống xử lý leo thang cơ học sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3cc08988-3b05-417e-8849-f5eb5c2fdc5e','e0044d62-7231-4269-975b-a32f8247391e',106,'image',NULL,'book/25-sales-os/21438925-c78d-443b-9566-c7879797f149-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b30e4e83-8af6-4e5d-bcdc-2bd480a7c9f9','25-sales-os','e8bf9b7d-9f22-4dd1-8812-b8887877359a',3,'Phương Trình Đo Lường Tính Kỷ Luật Thời Gian','phuong-trinh-o-luong-tinh-ky-luat-thoi-gian',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('61f36a22-aec6-4786-9e26-0da5603c6453','b30e4e83-8af6-4e5d-bcdc-2bd480a7c9f9',107,'text','Hằng tuần, tại buổi họp giao ban khối, *Sales Manager* nghiệm thu năng lực hành vi của đội ngũ thông qua công thức toán học đo lường **Tỷ lệ Đạt Chuẩn Phản Hồi Hệ Thống (SLA Attainment Rate)** trích xuất dữ liệu từ phần mềm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd486fc4-3ea9-429b-831d-395fded3b452','b30e4e83-8af6-4e5d-bcdc-2bd480a7c9f9',108,'image',NULL,'book/25-sales-os/8811425e-6c20-4332-82bd-dfb755d03e9e-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8aa4525-116c-418c-9be3-1693e4b43940','b30e4e83-8af6-4e5d-bcdc-2bd480a7c9f9',109,'text','**Ngưỡng nghiệm thu an toàn:** Chỉ số \\text{SLA Attainment Rate} của toàn đội ngũ bắt buộc phải luôn đạt mốc **\\ge**** 95%**. Bất kỳ nhân sự nào có chỉ số này tụt xuống dưới 90% trong 2 tuần liên tiếp sẽ lập tức bị đình chỉ quyền tiếp nhận Lead nóng từ các chiến dịch Paid Ads có ngân sách lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('18bfe961-8df8-46d3-8fae-30258cbc346d','b30e4e83-8af6-4e5d-bcdc-2bd480a7c9f9',110,'text','**Mantra tối thượng của Kỷ luật SLA:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('74777f4e-4568-45a7-8713-9f72d1d5210f','b30e4e83-8af6-4e5d-bcdc-2bd480a7c9f9',111,'text','*"Tốc độ phản hồi chính là lời tuyên ngôn đầu tiên về sự tử tế và tính chuyên nghiệp của phòng khám. Đừng để bệnh nhân phải chờ đợi trong sự hoài nghi và đau đớn sinh học. Trả lời chậm một phút là bạn đang tự tay dâng nụ cười của bệnh nhân cho đối thủ cạnh tranh."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('553d2dec-75a6-4918-823f-239ad2b39600','25-sales-os',NULL,2,'25.9 Cấu Trúc Đội Ngũ Nhân Sự Và Sơ Đồ Phân Nhiệm Trong Sales OS','259-cau-truc-oi-ngu-nhan-su-va-so-o-phan-nhiem-trong-sales-os',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('043a8bf9-7a20-4ec8-90f3-2924f2956dcc','553d2dec-75a6-4918-823f-239ad2b39600',112,'text','Một đường ống chuyển đổi dữ liệu thông minh trên CRM không thể tự vận hành nếu thiếu đi một cấu trúc nhân sự được quy hoạch cơ học, rõ ràng về mặt chức năng và đồng bộ về mặt mục tiêu. Sai lầm lớn nhất của các phòng khám nha khoa quy mô nhỏ là "bắt một nhân sự làm tất cả": Vừa trực inbox, vừa gọi telesales, vừa đón tiếp lễ tân và vừa kiêm luôn việc báo giá phác đồ lớn tại ghế nha. Cách sắp xếp chắp vá này trực tiếp tạo ra sự quá tải tâm lý, làm rò rỉ dữ liệu khách hàng tiềm năng và suy giảm nghiêm trọng trải nghiệm an tâm của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a938ba7e-7354-4602-80cc-f43f68173686','553d2dec-75a6-4918-823f-239ad2b39600',113,'text','*Sales OS* phân rã bộ máy thành 5 vị trí chuyên biệt có tính kế thừa và chuyển giao dữ liệu liên tục:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ec0dfc8-bfd0-4742-8afd-07bf998d80a1','553d2dec-75a6-4918-823f-239ad2b39600',114,'image',NULL,'book/25-sales-os/05742910-cabd-44c9-9208-59eb12565c2e-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ecda10d0-3d82-4ae1-bd7f-5dbb7b6fd8c4','25-sales-os','553d2dec-75a6-4918-823f-239ad2b39600',3,'Đặc Tả Chi Tiết Role Card Năng Lực Vị Trí (Job Specifications)','ac-ta-chi-tiet-role-card-nang-luc-vi-tri-job-specifications',37,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('392558de-e3aa-4286-90d0-a9aabe082b6f','25-sales-os','ecda10d0-3d82-4ae1-bd7f-5dbb7b6fd8c4',4,'Sales Manager (Trưởng bộ phận kinh doanh / Tư vấn trưởng)','sales-manager-truong-bo-phan-kinh-doanh-tu-van-truong',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98179cce-2726-40e8-bf91-d4b39cfeed87','392558de-e3aa-4286-90d0-a9aabe082b6f',115,'text','Đây là kiến trúc sư trưởng điều khiển đường ống chuyển đổi của phòng khám, chịu trách nhiệm tối cao về tính mượt mà của dòng chảy dữ liệu từ trực tuyến xuống sàn vật lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36c7ef40-c18e-4a2a-af67-d86cef29ad31','392558de-e3aa-4286-90d0-a9aabe082b6f',116,'text','- **Nhiệm vụ cốt lõi hằng ngày:**Giám sát và kiểm toán toàn bộ hệ thống Master Pipeline trên CRM, phát hiện sớm các hồ sơ lead bị tồn đọng quá 24 giờ.- Nghe lại ghi âm cuộc gọi mẫu, đọc ngẫu nhiên tin nhắn trực inbox hằng tuần để chấm điểm chất lượng hội thoại của nhân sự.- Liên tục tiến hành tinh chỉnh, viết lại các kịch bản xử lý từ chối về giá dựa trên dữ liệu cập nhật ngoài thực địa.- Đóng vai trò làm trọng tài liên OS: Phối hợp với *Marketing OS* để kiểm duyệt chất lượng lead đầu vào và liên kết với *Clinic OS* để tối ưu lịch trống của Bác sĩ.- Xuất báo cáo định lượng về tỷ lệ chuyển đổi tài chính trích xuất trực tiếp lên ban giám đốc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c610cffd-00d6-4746-bb7a-760929e970fc','25-sales-os','ecda10d0-3d82-4ae1-bd7f-5dbb7b6fd8c4',4,'Tư vấn viên Online (Online Consultant / Chat Agent)','tu-van-vien-online-online-consultant-chat-agent',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7f4bc7a-1984-4205-ba88-7c4cc2bea699','c610cffd-00d6-4746-bb7a-760929e970fc',117,'text','Mắt xích trực chiến tuyến đầu trên không gian mạng, chịu trách nhiệm phá băng nhận thức và khơi thông mong muốn đến phòng khám của lead lạnh/lead ấm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c9402b9-9c79-423c-8dd3-2fba0c4c913e','c610cffd-00d6-4746-bb7a-760929e970fc',118,'text','- **Nhiệm vụ cốt lõi hằng ngày:**Trực ca liên tục, đảm bảo SLA tốc độ phản hồi tin nhắn từ Facebook, TikTok, Website và Zalo OA luôn nằm trong ngưỡng an toàn.- Thực thi kịch bản đặt câu hỏi mở để bóc tách 5 khung thông tin điểm đau sinh học và rào cản tài chính của bệnh nhân.- Sử dụng linh hoạt kho tài sản bằng chứng thực chứng (`Trust Assets Library`) gửi đúng thời điểm để sưởi ấm lòng tin khách hàng.- Điều hướng cuộc hội thoại đi đến hành động đặt lịch hẹn, tạo lập mã khách hàng chính xác trên CRM.- Chạy luồng follow-up kỷ luật hằng tuần đối với nhóm khách hàng hỏi giá rồi im lặng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eb68c838-ba24-439d-a772-67b5661d3ebe','25-sales-os','ecda10d0-3d82-4ae1-bd7f-5dbb7b6fd8c4',4,'Telesales / Booking Agent (Điều phối lịch hẹn hệ thống)','telesales-booking-agent-ieu-phoi-lich-hen-he-thong',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3025fc9a-ee3c-4a65-8dbe-830eb5f0786a','eb68c838-ba24-439d-a772-67b5661d3ebe',119,'text','Hệ thống van điều tiết giọng nói trực tiếp qua hotline tổng đài, chịu trách nhiệm biến các mã đặt lịch ảo thành cam kết có mặt thực sàn của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff4d2372-08a0-4f5c-9991-d08d05e8fe67','eb68c838-ba24-439d-a772-67b5661d3ebe',120,'text','- **Nhiệm vụ cốt lõi hằng ngày:**Thực hiện cuộc gọi phá băng cấp tốc đối với các Lead Form nóng để khóa chặt nhu cầu khẩn cấp.- Vận hành quy trình nhắc lịch chu kỳ hai tầng thời gian (Trước 24 giờ và Trước 2 giờ) bằng tông giọng thấu cảm, tử tế để dập tắt tỷ lệ No-show.- Chủ động dời lịch, xử lý linh hoạt các tình huống khách bận đột xuất, không để ghế nha rơi vào trạng thái trống công suất.- Kích hoạt các chiến dịch gọi điện tái chăm sóc, gửi lời chúc mừng sinh nhật, hoặc thông báo chương trình bảo trì răng sứ định kỳ cho tệp khách hàng cũ ngủ đông.- Kích hoạt đường ống Follow-up hậu thăm khám đối với nhóm khách hàng đã chụp phim nhưng chưa điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9f1440f8-babf-4658-96e3-85a7ca6c083d','25-sales-os','ecda10d0-3d82-4ae1-bd7f-5dbb7b6fd8c4',4,'Lễ tân / Front Desk (Gương mặt đại diện tại phòng khám)','le-tan-front-desk-guong-mat-ai-dien-tai-phong-kham',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ef52f7c-9db9-4e42-8364-a6cb19a829ca','9f1440f8-babf-4658-96e3-85a7ca6c083d',121,'text','Điểm chạm vật lý đầu tiên tạo lập mỏ neo cảm xúc an toàn, hạnh phúc khi bệnh nhân bước chân qua cửa phòng khám tại Hà Nội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb34b22d-197b-4e55-ae53-5f36386cbcc6','9f1440f8-babf-4658-96e3-85a7ca6c083d',122,'text','- **Nhiệm vụ cốt lõi hằng ngày:**Tiếp đón bệnh nhân bằng nụ cười rạng rỡ chuẩn SLA dịch vụ 5 sao, thực hiện check-in mã hẹn trên hệ thống CRM cấp tốc dưới 60 giây.- Đối soát, kiểm tra độ chính xác của thông tin cá nhân và cập nhật trạng thái dữ liệu khách từ `Booked` sang `Arrived`.- Tiếp nhận gói bàn giao dữ liệu (Handoff Payload) từ bộ phận online, chuyển giao trọn vẹn thông tin điểm đau và nỗi sợ của khách cho Bác sĩ trưởng ca.- Điều phối nhịp điệu di chuyển của bệnh nhân giữa sảnh chờ, phòng chụp phim CT Cone Beam và các ghế điều trị lâm sàng, không để xảy ra tình trạng tắc nghẽn sảnh nha.- Hỗ trợ trải nghiệm tại sàn: Phục vụ nước uống, hướng dẫn khu vực vô trùng, tạo không gian thư thái bẻ gãy nỗi sợ tiếng máy khoan cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('507f4523-48b7-4be2-bf15-5f61c29d2a32','25-sales-os','ecda10d0-3d82-4ae1-bd7f-5dbb7b6fd8c4',4,'Treatment Coordinator (Chuyên viên điều phối lâm sàng VIP - TCO)','treatment-coordinator-chuyen-vien-ieu-phoi-lam-sang-vip-tco',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9bb20261-5bae-472c-afc5-92b0e4bfee76','507f4523-48b7-4be2-bf15-5f61c29d2a32',123,'text','Vị trí vũ khí tối tân đặc biệt phù hợp cho phòng khám đẩy mạnh dòng dịch vụ can thiệp sâu có giá trị cao (High-Ticket) như cấy ghép Implant toàn hàm hay chỉnh nha Invisalign. TCO là cầu nối hoàn hảo giữa chuyên môn hàn lâm của Bác sĩ và năng lực chi trả tài chính của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f032924-59bb-43a0-9ff8-74bc4090bb17','507f4523-48b7-4be2-bf15-5f61c29d2a32',124,'text','**Nhiệm vụ cốt lõi hằng ngày:**Tiếp quản bệnh nhân ngay sau khi Bác sĩ hoàn tất bước chẩn đoán lâm sàng. Ngồi riêng với khách tại phòng VIP để giải thích lại phác đồ bằng ngôn từ bình dân thường thức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c63314d9-3954-46fc-bc96-b7d07942dd4b','507f4523-48b7-4be2-bf15-5f61c29d2a32',125,'text','Bóc tách chi tiết cấu trúc chi phí trọn gói, giải thích tính minh bạch của vật liệu y tế, khẳng định chính sách bảo hành bằng văn bản pháp lý của nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('280ca54c-baea-4715-ada7-990004cdb627','507f4523-48b7-4be2-bf15-5f61c29d2a32',126,'text','Tư vấn giải pháp đòn bẩy dòng tiền: Hướng dẫn cấu hình hồ sơ trả góp 0% qua hệ thống ngân hàng liên kết, chia nhỏ gánh nặng tài chính cho khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('81d1ecf4-c441-4340-b1af-4156b3d10ca7','507f4523-48b7-4be2-bf15-5f61c29d2a32',127,'text','Chịu chỉ tiêu trực tiếp về chỉ số `Case Acceptance Rate` (Tỷ lệ đồng ý điều trị phương án ca lớn).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ccf27d83-1ad4-4faf-9e88-06ea686a682d','507f4523-48b7-4be2-bf15-5f61c29d2a32',128,'text','Thực hiện luồng bám đuổi chuyên sâu (Follow-up) hằng ngày đối với các ca lâm sàng VIP hoãn quyết định do rào cản gia đình hoặc tài chính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef660bbd-cdcf-4b31-914e-c3dfb58f605a','507f4523-48b7-4be2-bf15-5f61c29d2a32',129,'text','**Mantra điều hành cấu trúc đội ngũ:***"Một team Sales OS xuất sắc không hoạt động dựa trên những cá nhân kiệt xuất có tài chèo kéo, chốt sale bẩm sinh. Nó hoạt động như một dây chuyền chuyển giao năng lượng khép kín, nơi mỗi nhân sự làm tốt nhất một nhiệm vụ chuyên biệt của mình theo đúng thiết kế mã lệnh quy trình, bảo đảm dữ liệu tự động chảy, niềm tin tự động dày và doanh thu tự động bứt phá."*',NULL,NULL,NULL,NULL,NULL);
